import { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, FunctionDeclaration, Type, Tool } from '@google/genai';
import { createPcmBlob, decodeAudioData, PCM_SAMPLE_RATE } from '../services/audioUtils';
import { AppState, VisualContent, EyeState } from '../types';

const endSessionTool: FunctionDeclaration = {
  name: "end_session",
  description: "Ends the voice session. Use when user is done.",
  parameters: { type: Type.OBJECT, properties: {} }
};

const display_image: FunctionDeclaration = {
  name: "display_image",
  description: "Displays an image from a URL. Must use a direct image link.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      url: { type: Type.STRING },
      caption: { type: Type.STRING }
    },
    required: ["url"]
  }
};

const close_visual: FunctionDeclaration = {
  name: "close_visual",
  description: "Closes any currently displayed image or widget. Use this when the conversation moves on from the visual.",
  parameters: { type: Type.OBJECT, properties: {} }
};

const render_widget: FunctionDeclaration = {
  name: "render_widget",
  description: "Renders an interactive UI widget.",
  parameters: {
    type: Type.OBJECT,
    properties: {
      html: { type: Type.STRING },
      css: { type: Type.STRING },
      javascript: { type: Type.STRING },
      title: { type: Type.STRING }
    },
    required: ["html"]
  }
};

const tools: Tool[] = [
  { functionDeclarations: [endSessionTool, display_image, render_widget, close_visual] },
  { codeExecution: {} } 
];

export const useGeminiLive = (apiKey: string | undefined, onDisconnect: () => void) => {
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [connectionState, setConnectionState] = useState<AppState>(AppState.IDLE);
  const [visualContent, setVisualContent] = useState<VisualContent | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const connectionStateRef = useRef<AppState>(AppState.IDLE);
  const connectionIdRef = useRef<number>(0);
  const videoIntervalRef = useRef<any>(null);

  useEffect(() => { connectionStateRef.current = connectionState; }, [connectionState]);

  const cleanup = async () => {
      if (videoIntervalRef.current) clearInterval(videoIntervalRef.current);
      if (processorRef.current) {
          processorRef.current.disconnect();
          processorRef.current = null;
      }
      if (streamRef.current) {
          streamRef.current.getTracks().forEach(t => t.stop());
          streamRef.current = null;
      }
      if (inputContextRef.current) {
          await inputContextRef.current.close().catch(() => {});
          inputContextRef.current = null;
      }
      if (audioContextRef.current) {
          await audioContextRef.current.close().catch(() => {});
          audioContextRef.current = null;
      }
      await new Promise(r => setTimeout(r, 200));
  };

  const disconnect = useCallback(async () => {
      connectionIdRef.current++;
      sourcesRef.current.forEach(s => { try { s.stop(); } catch(e){} });
      sourcesRef.current.clear();
      setIsThinking(false);
      setIsAiSpeaking(false);
      await cleanup();
      setConnectionState(AppState.IDLE);
      onDisconnect();
  }, [onDisconnect]);

  const connect = async (retryCount = 0): Promise<void> => {
    if (!apiKey) return;
    const currentId = ++connectionIdRef.current;

    try {
      setConnectionState(AppState.CONNECTING);
      await cleanup();

      const ai = new GoogleGenAI({ apiKey });
      inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: PCM_SAMPLE_RATE });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      // Request both audio and video with retry logic to handle mic contention
      let stream: MediaStream | null = null;
      let attempt = 0;
      while (!stream && attempt < 5) {
          if (currentId !== connectionIdRef.current) return;
          try {
             stream = await navigator.mediaDevices.getUserMedia({ 
                audio: true,
                video: { width: { ideal: 640 }, height: { ideal: 480 }, frameRate: { ideal: 10 } }
             });
          } catch (e: any) {
              console.warn(`Mic/Cam acquisition failed (attempt ${attempt + 1}/5):`, e.message);
              // Wait for WakeWordDetector to fully release the mic
              await new Promise(r => setTimeout(r, 400));
              attempt++;
          }
      }

      if (!stream) throw new Error("Could not acquire microphone/camera after retries");

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: async () => {
            if (currentId !== connectionIdRef.current) return;
            try {
                if (!stream) return; // Should not happen
                streamRef.current = stream;
                setConnectionState(AppState.ACTIVE);

                // Audio Streaming
                if (!inputContextRef.current) return;
                const source = inputContextRef.current.createMediaStreamSource(stream);
                const scriptProcessor = inputContextRef.current.createScriptProcessor(4096, 1, 1);
                processorRef.current = scriptProcessor;
                scriptProcessor.onaudioprocess = (e) => {
                  if (connectionStateRef.current !== AppState.ACTIVE || currentId !== connectionIdRef.current) return;
                  const inputData = e.inputBuffer.getChannelData(0);
                  const pcmBlob = createPcmBlob(inputData);
                  sessionPromise.then((session: any) => {
                    try { session.sendRealtimeInput({ media: pcmBlob }); } catch (err) {}
                  });
                };
                source.connect(scriptProcessor);
                scriptProcessor.connect(inputContextRef.current.destination);

                // Video Streaming (Frames)
                const videoEl = document.createElement('video');
                videoEl.srcObject = stream;
                videoEl.play();
                const canvas = document.createElement('canvas');
                const ctx = canvas.getContext('2d');

                videoIntervalRef.current = setInterval(() => {
                    if (connectionStateRef.current !== AppState.ACTIVE || currentId !== connectionIdRef.current) return;
                    if (ctx && videoEl.readyState >= 2) {
                        canvas.width = 320;
                        canvas.height = 240;
                        ctx.drawImage(videoEl, 0, 0, canvas.width, canvas.height);
                        const base64Data = canvas.toDataURL('image/jpeg', 0.5).split(',')[1];
                        sessionPromise.then(session => {
                            session.sendRealtimeInput({ media: { data: base64Data, mimeType: 'image/jpeg' } });
                        });
                    }
                }, 1000); // 1 frame per second

            } catch (err) { disconnect(); }
          },
          onmessage: async (message: LiveServerMessage) => {
            if (currentId !== connectionIdRef.current) return;

            // Handle Audio
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio && audioContextRef.current) {
              const ctx = audioContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);
              setIsAiSpeaking(true);
              setIsThinking(false);
              source.onended = () => {
                  sourcesRef.current.delete(source);
                  if (sourcesRef.current.size === 0) setIsAiSpeaking(false);
              };
              source.start(nextStartTimeRef.current);
              sourcesRef.current.add(source);
              nextStartTimeRef.current += audioBuffer.duration;
            }

            // Handle Tool Calls
            if (message.toolCall) {
                setIsThinking(true);
                const session = await sessionPromise;
                const functionResponses: any[] = [];
                for (const fc of message.toolCall.functionCalls) {
                    let result: any = { status: "ok" };
                    if (fc.name === 'end_session') { disconnect(); return; }
                    else if (fc.name === 'display_image') {
                        setVisualContent({ type: 'image', content: (fc.args as any).url, title: (fc.args as any).caption || 'Image Content' });
                        result = { result: "Image rendered" };
                    }
                    else if (fc.name === 'close_visual') {
                        setVisualContent(null);
                        result = { result: "Visual display closed" };
                    }
                    else if (fc.name === 'render_widget') {
                        setVisualContent({ type: 'widget', content: (fc.args as any).html, title: (fc.args as any).title || 'Widget' });
                        result = { result: "Widget rendered" };
                    }
                    functionResponses.push({ id: fc.id, name: fc.name, response: result });
                }
                if (functionResponses.length > 0) session.sendToolResponse({ functionResponses });
            }

            if (message.serverContent?.interrupted) {
                sourcesRef.current.forEach(s => { try{s.stop()}catch(e){} });
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
                setIsAiSpeaking(false);
                setIsThinking(false);
            }
          },
          onclose: () => { if (currentId === connectionIdRef.current) disconnect(); },
          onerror: (err) => {
              console.error("Critical Connection Error:", err);
              if (retryCount < 2) setTimeout(() => connect(retryCount + 1), 1000);
              else { setConnectionState(AppState.ERROR); setTimeout(disconnect, 2000); }
          }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            tools: tools,
            thinkingConfig: { thinkingBudget: 0 }, // 0 for lowest latency (Voice Assistant mode)
            systemInstruction: `You are Airo, a helpful and snappy voice assistant with vision capabilities.
            - You can see the user via their camera.
            - Keep responses concise, natural, and friendly.
            - When showing visual content, use 'display_image' or 'render_widget'.
            - Call 'close_visual' when the visual is no longer needed.
            - Call 'end_session' if the user says goodbye or wants to stop.`,
        }
      });
    } catch (e) {
      console.error(e);
      setConnectionState(AppState.ERROR);
      setTimeout(disconnect, 2000);
    }
  };

  return { connect, disconnect, isAiSpeaking, isThinking, connectionState, visualContent, setVisualContent };
};

function decode(base64: string) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
  return bytes;
}

import React, { useEffect, useState, useRef } from 'react';
import { Eyes } from './components/Eyes';
import { VisualDisplay } from './components/VisualDisplay';
import { useGeminiLive } from './hooks/useGeminiLive';
import { WakeWordDetector } from './services/wakeWord';
import { AppState, EyeState } from './types';

// Version: 1.5.0 - Wake Word Optimization & Fast Response
export default function App() {
  const [hasStarted, setHasStarted] = useState(false);
  const [wakeState, setWakeState] = useState(false); 
  const [isPreparing, setIsPreparing] = useState(false);
  const [lastHeard, setLastHeard] = useState("");
  const wakeWordRef = useRef<WakeWordDetector | null>(null);
  const holdTimerRef = useRef<any>(null);

  const { connect, disconnect, isAiSpeaking, isThinking, connectionState, visualContent, setVisualContent } = useGeminiLive(
    process.env.API_KEY, 
    () => {
        setWakeState(false);
        setIsPreparing(false);
    }
  );

  useEffect(() => {
    wakeWordRef.current = new WakeWordDetector(
        () => {
            if (connectionState === AppState.IDLE && !isPreparing) {
                setWakeState(true);
                setLastHeard("Wake Word Detected!");
            }
        },
        (text) => setLastHeard(text)
    );
    return () => wakeWordRef.current?.stop();
  }, [connectionState, isPreparing]);

  useEffect(() => {
    let timeoutId: any;

    if (wakeState && connectionState === AppState.IDLE) {
        setIsPreparing(true);
        wakeWordRef.current?.stop();

        // Short delay to ensure wake word detector has time to release mic
        // The useGeminiLive hook has retry logic if mic is still busy
        timeoutId = setTimeout(() => {
            if (wakeState) {
                connect().finally(() => setIsPreparing(false));
            }
        }, 300);

    } else if (!wakeState && hasStarted && connectionState === AppState.IDLE) {
        disconnect();
        timeoutId = setTimeout(() => {
             if (!wakeState && !isPreparing) {
                wakeWordRef.current?.start();
             }
        }, 800);
    }

    return () => clearTimeout(timeoutId);
  }, [wakeState, hasStarted, connectionState]);

  let eyeState = EyeState.IDLE;
  if (connectionState === AppState.ACTIVE) {
      if (isThinking) eyeState = EyeState.THINKING;
      else if (isAiSpeaking) eyeState = EyeState.SPEAKING;
      else eyeState = EyeState.LISTENING;
  } else if (connectionState === AppState.CONNECTING || isPreparing) {
      eyeState = EyeState.LISTENING;
  }

  const handleStart = () => {
      setHasStarted(true);
      wakeWordRef.current?.start();
  };

  const handlePointerDown = () => {
      if (!hasStarted || isPreparing || connectionState !== AppState.IDLE) return;
      holdTimerRef.current = setTimeout(() => {
          setWakeState(true);
          setLastHeard("Manual Hold Triggered");
      }, 700);
  };

  const handlePointerUp = () => {
      if (holdTimerRef.current) {
          clearTimeout(holdTimerRef.current);
          holdTimerRef.current = null;
      }
  };

  if (!hasStarted) {
    return (
      <div className="h-screen w-screen bg-black flex flex-col items-center justify-center text-white gap-4">
        <button 
            onClick={handleStart}
            className="px-8 py-4 bg-gray-900 border border-gray-700 rounded-full hover:bg-gray-800 transition-all font-mono text-xl shadow-[0_0_20px_rgba(255,255,255,0.2)]"
        >
          Initialize Airo System
        </button>
        <p className="text-gray-500 text-sm">Vision & Voice Active (v1.5.0)</p>
      </div>
    );
  }

  return (
    <div 
        className="relative h-screen w-screen overflow-hidden select-none bg-black"
        onPointerDown={handlePointerDown}
        onPointerUp={handlePointerUp}
        onPointerLeave={handlePointerUp}
    >
      <Eyes state={eyeState} />

      <VisualDisplay 
        data={visualContent} 
        onDismiss={() => setVisualContent(null)} 
      />

      <div className="absolute bottom-6 left-0 right-0 flex flex-col items-center pointer-events-none gap-3 z-10">
          <span className={`inline-block w-2.5 h-2.5 rounded-full transition-all duration-700 ${
              connectionState === AppState.ACTIVE ? 'bg-green-500 shadow-[0_0_15px_#22c55e]' : 
              connectionState === AppState.CONNECTING || isPreparing ? 'bg-yellow-500 animate-pulse' : 
              connectionState === AppState.ERROR ? 'bg-red-500' : 'bg-white/5'
          }`}></span>

          <div className="text-gray-500 font-mono text-[10px] uppercase tracking-[0.2em] opacity-60 text-center px-4 max-w-xs truncate">
              {isPreparing ? "Calibrating Sensors..." : (lastHeard || "Awaiting 'Hey Airo'")}
          </div>

          {connectionState === AppState.ERROR && (
              <div className="text-red-500 font-mono text-xs animate-pulse bg-red-900/10 px-3 py-1 rounded-full border border-red-900/20">
                  SYSTEM BUSY - RECONNECTING
              </div>
          )}
      </div>
    </div>
  );
}

export class WakeWordDetector {
  recognition: any;
  isListening: boolean = false;
  onWake: () => void;

  constructor(onWake: () => void, onTranscript?: (text: string) => void) {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      console.warn("Speech Recognition not supported in this browser.");
      return;
    }
    this.recognition = new SpeechRecognition();
    this.recognition.continuous = true;
    this.recognition.interimResults = true; // Enable interim results for faster matching
    this.recognition.lang = 'en-US';
    this.onWake = onWake;

    this.recognition.onresult = (event: any) => {
      let transcript = '';
      for (let i = event.resultIndex; i < event.results.length; ++i) {
        transcript += event.results[i][0].transcript;
      }

      const lower = transcript.trim().toLowerCase();
      console.log("Wake Word Listener heard:", lower);

      if (onTranscript) {
          onTranscript(lower);
      }

      // Expanded keyword spotting for "Airo"
      const triggers = [
          "airo", "arrow", "aero", 
          "hey airo", "hey arrow", "hey aero",
          "hero", "harrow", "air oh",
          "hey row", "arrow", "hi ro", "i row",
          "hello airo", "ok airo"
      ];

      if (triggers.some(t => lower.includes(t))) {
         this.onWake();
         // Abort immediately to release mic
         this.stop();
      }
    };

    this.recognition.onend = () => {
        if (this.isListening) {
            try {
              this.recognition.start();
            } catch (e) {
              // Ignore errors if already started
            }
        }
    };

    this.recognition.onerror = (event: any) => {
        if (event.error === 'no-speech' || event.error === 'aborted') {
            return;
        }
        console.error("Wake word error", event.error);
    };
  }

  start() {
    if (!this.recognition) return;
    this.isListening = true;
    try {
        this.recognition.start();
    } catch(e) { 
        // Already started?
    }
  }

  stop() {
    if (!this.recognition) return;
    this.isListening = false;
    try {
        // abort() stops immediately and does not return results, freeing the mic faster than stop()
        this.recognition.abort();
    } catch(e) {}
  }
}
